+                let src = &ag.nodes[0];
+                let dst = &ag.nodes[ag.nodes.len() - 1];
+                let _ = fnx_algorithms::shortest_path_unweighted(&ag.graph, src, dst);
+            }
+        }
+        ShortestPathInput::UnweightedDirected(ag) => {
+            if ag.nodes.len() >= 2 {
+                let src = &ag.nodes[0];
